	// Build per-kind spec schemas from StepSpec via reflection.
	specType := derefType(reflect.TypeOf(pipeline.StepSpec{}))
	for _, sk := range pipeline.StepKinds {
		defs[sk.DefName] = buildKindSpec(specType, sk, defs, renames)
	}

	return Schema{
		"type":     "object",
		"required": []string{"id", "kind", "spec"},
		"properties": Schema{
			"id":      Schema{"type": "string"},
			"kind":    Schema{"type": "string", "enum": strSliceToIface(stepKindNames)},
			"require": ref(renameRef("RequireConfig", renames)),
			"spec":    Schema{},
		},
		"additionalProperties": false,
		"allOf":                buildKindConditionals(stepKindNames, renames),
	}
